if (!hasCall) {
  // Count stores per pointer (include subloop blocks too — we need to know
  // whether ANY store in the entire loop nest writes to this pointer).
  std::unordered_map<Value*, unsigned> storeCount;
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        storeCount[si->getPointerOperand()]++;
      }
    }
  }
  // Also abort if any subloop has calls.
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (isa<CallBase>(I)) {
        hasCall = true;
        break;
      }
    }
    if (hasCall)
      break;
  }
  if (!hasCall) {
    for (auto* bb : L->blocks()) {
      // Only hoist stores from blocks directly owned by L (we don't have a
      // preheader for subloops anyway).
      if (LI.getLoopFor(bb) != L)
        continue;
      for (auto& I : *bb) {
        auto si = dyn_cast<StoreInst>(&I);
        if (!si)
          continue;
        Value* ptr = si->getPointerOperand();
        Value* val = si->getValueOperand();
        if (!isLoopInvariantValue(ptr, L))
          continue;
        if (!isLoopInvariantValue(val, L))
          continue;
        if (!isLocalAllocaBacked(ptr))
          continue;
        if (storeCount[ptr] != 1)
          continue;
        storesToHoist.push_back(si);
      }
    }
    for (auto* si : storesToHoist) {
      si->moveBefore(insertPt);
      changed = true;
    }
  }
}

