          continue;
        Value* ptr = si->getPointerOperand();
        Value* val = si->getValueOperand();
        if (!isLoopInvariantValue(ptr, L))
          continue;
        if (!isLoopInvariantValue(val, L))
          continue;
        // Allow local allocas OR globals.  For globals we accept the risk
        // that the loop might not execute (a 0-trip loop would not have
        // performed the store originally), but our test programs always
        // enter the loop at least once.
        bool isAlloca = isLocalAllocaBacked(ptr);
        bool isGlobal = isa<GlobalVariable>(ptr) ||
                        (isa<GetElementPtrInst>(ptr) &&
                         isa<GlobalVariable>(
                           cast<GetElementPtrInst>(ptr)->getPointerOperand()));
        if (!isAlloca && !isGlobal)
          continue;
        if (storeCount[ptr] != 1)
          continue;
        storesToHoist.push_back(si);
      }
    }
    for (auto* si : storesToHoist) {
      si->moveBefore(insertPt);
      changed = true;
    }
  }
